  (() => {
    // Schritt 1: Filtere die Daten aus Chart1 basierend auf den Bedingungen
    const records = Chart.tableData
      .filter(p => p.company_name === SelectAccount.selectedOptionValue); // Account-Filter hinzufügen

    // Schritt 2: Zeitraum bestimmen (minDate aus Daten, maxDate als aktueller Monat)
    const dates = records.map(p => new Date(p.month));
    const minDate = new Date(Math.min(...dates));
    const maxDate = new Date(); // Aktueller Monat

    // Schritt 3: Alle Monate zwischen minDate und maxDate generieren
    const allMonths = [];
    let current = new Date(minDate.getFullYear(), minDate.getMonth(), 1);
    while (current <= maxDate) {
      allMonths.push(current.getFullYear() + '-' + (current.getMonth() + 1).toString().padStart(2, '0'));
      current.setMonth(current.getMonth() + 1); // Zum nächsten Monat wechseln
    }

    // Schritt 4: Daten gruppieren und summieren
    const groupedData = records.reduce((acc, p) => {
      const month = new Date(p.month).getFullYear() + '-' + (new Date(p.month).getMonth() + 1).toString().padStart(2, '0');
      if (!acc[month]) acc[month] = 0;
      acc[month] += p.booking; // Summiere die booking-Werte
      return acc;
    }, {});

    // Schritt 5: Alle Monate sicherstellen und fehlende mit 0 auffüllen
    return allMonths.map(month => ({
      x: month,
      y: groupedData[month] || 0 // Falls kein Wert existiert, setze 0
    }));
  })()
}}
